    question: "Check if value is defined in enum using Enum.IsDefined().",
    mathSolution: "Validating if integer/string is valid enum member.",
    codeSolution: "using System;\n\nenum ErrorCode\n{\n    None = 0,\n    NotFound = 404,\n    ServerError = 500,\n    Unauthorized = 401,\n    Forbidden = 403\n}\n\nclass Program\n{\n    static void Main()\n    {\n        int[] testValues = { 200, 404, 500, 401, 999 };\n        \n        foreach (int value in testValues)\n        {\n            bool isDefined = Enum.IsDefined(typeof(ErrorCode), value);\n            if (isDefined)\n            {\n                ErrorCode code = (ErrorCode)value;\n                Console.WriteLine($\"{value} is valid -> {code}\");\n            }\n            else\n            {\n                Console.WriteLine($\"{value} is NOT a valid ErrorCode\");\n            }\n        }\n        \n        // Check string names\n        string[] testNames = { \"None\", \"NotFound\", \"BadRequest\", \"ServerError\" };\n        \n        Console.WriteLine(\"\\nString validation:\");\n        foreach (string name in testNames)\n        {\n            bool isDefined = Enum.IsDefined(typeof(ErrorCode), name);\n            Console.WriteLine($\"  '{name}' is {(isDefined ? \"valid\" : \"invalid\")}\");\n        }\n    }\n}",
    hint: "Enum.IsDefined() checks if a value exists in the enum definition.",
