    id: "cs_enums_10",
    topicId: "cs_enums",
    question: "Use enum with Description attribute via reflection.",
    mathSolution: "Adding descriptive text to enum members.",
    codeSolution: "using System;\nusing System.ComponentModel;\nusing System.Reflection;\n\nenum OrderStatus\n{\n    [Description(\"Order has been placed but not processed\")]\n    Pending,\n    \n    [Description(\"Order is being prepared\")]\n    Processing,\n    \n    [Description(\"Order has been shipped\")]\n    Shipped,\n    \n    [Description(\"Order has been delivered to customer\")]\n    Delivered,\n    \n    [Description(\"Order was cancelled by customer\")]\n    Cancelled\n}\n\nclass Program\n{\n    static void Main()\n    {\n        OrderStatus status = OrderStatus.Shipped;\n        \n        Console.WriteLine($\"Status: {status}\");\n        Console.WriteLine($\"Description: {GetEnumDescription(status)}\");\n        \n        Console.WriteLine(\"\\nAll order statuses:\");\n        foreach (OrderStatus s in Enum.GetValues(typeof(OrderStatus)))\n        {\n            Console.WriteLine($\"  {s,-12} - {GetEnumDescription(s)}\");\n        }\n    }\n    \n    static string GetEnumDescription(Enum value)\n    {\n        FieldInfo field = value.GetType().GetField(value.ToString());\n        DescriptionAttribute attribute = field.GetCustomAttribute<DescriptionAttribute>();\n        return attribute == null ? value.ToString() : attribute.Description;\n    }\n}",
    hint: "Use DescriptionAttribute with reflection to add readable descriptions to enums.",
