    question: "Create enum with duplicate values (multiple names same value).",
    mathSolution: "Enum members can share same underlying value.",
    codeSolution: "using System;\n\nenum HttpStatus\n{\n    OK = 200,\n    Success = 200,\n    Created = 201,\n    BadRequest = 400,\n    NotFound = 404,\n    NotFoundError = 404\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Console.WriteLine(\"HTTP Status Codes with duplicates:\");\n        \n        HttpStatus status1 = HttpStatus.OK;\n        HttpStatus status2 = HttpStatus.Success;\n        \n        Console.WriteLine($\"OK = {(int)status1}\");\n        Console.WriteLine($\"Success = {(int)status2}\");\n        Console.WriteLine($\"Are they equal? {status1 == status2}\");\n        \n        Console.WriteLine(\"\\nAll values (including duplicates):\");\n        foreach (string name in Enum.GetNames(typeof(HttpStatus)))\n        {\n            HttpStatus value = (HttpStatus)Enum.Parse(typeof(HttpStatus), name);\n            Console.WriteLine($\"  {name} = {(int)value}\");\n        }\n        \n        Console.WriteLine(\"\\nNote: ToString() returns first defined name for duplicate values\");\n        HttpStatus notFound = HttpStatus.NotFound;\n        Console.WriteLine($\"HttpStatus.NotFound = {notFound}\");\n    }\n}",
